#include "fingerprint_r307.h"
#include <Adafruit_Fingerprint.h>
#include <HardwareSerial.h>
static HardwareSerial fpSerial(2);
static Adafruit_Fingerprint finger(&fpSerial);
void fingerprint_setup(){
  fpSerial.begin(57600,SERIAL_8N1,16,17);
  finger.begin(57600);
  if(!finger.verifyPassword()){Serial.println("[fp] Sensor not found!");return;}
  Serial.printf("[fp] OK, %d templates\n",finger.templateCount);
}
void fingerprint_loop(){}
int fingerprint_verify(){
  if(finger.getImage()!=FINGERPRINT_OK)return-1;
  if(finger.image2Tz()!=FINGERPRINT_OK)return-2;
  if(finger.fingerSearch()!=FINGERPRINT_OK)return-3;
  return finger.fingerID;
}
int fingerprint_get_count(){finger.getTemplateCount();return finger.templateCount;}
